from typing import List

def getModifiedArray(length: int, updates: List[List[int]]) -> List[int]:
    result = [0] * length

    for start, end, inc in updates:
        result[start] += inc
        if end + 1 < length:
            result[end + 1] -= inc

    # Prefix sum to propagate range increments
    for i in range(1, length):
        result[i] += result[i - 1]

    return result
